map "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/NutritionSugarSaltyFrequencyQuestionnaireResponseToObservation" = "NutritionSugarSaltyFrequencyQuestionnaireResponseToObservation"

/// url = "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/NutritionSugarSaltyFrequencyQuestionnaireResponseToObservation"
/// name = "NutritionSugarSaltyFrequencyQuestionnaireResponseToObservation"
/// title = "Nutrition Sugar Salty Frequency Q to O"
/// status = "active"

uses "http://hl7.org/fhir/StructureDefinition/QuestionnaireResponse" alias QR as source
uses "http://hl7.org/fhir/StructureDefinition/Observation" alias Obs as target

imports "http://hl7.org/fhir/StructureMap/*"
imports "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/QuestionnaireResponseToObservationBase"

group NutritionSugarSaltyFrequencyQuestionnaireResponseToObservation(source src : QR, target tgt : Obs) {
  src then SetObservationBase(src, tgt) "Base";
  src -> tgt.meta = create('Meta') as meta,
    meta.profile = 'https://fhir.hl7.at/prenudge/appdata/r4/StructureDefinition/at-prenudge-nutrition-sugarsalty-observation' "SetProfile";
  src -> tgt.code = cc('http://snomed.info/sct', '364395008', 'Pattern of food and drink intake (observable entity)') "SetCode";
  src.item as item where linkId = 'DH6' then MapSugarSaltyFrequency(item, tgt) "ProcessDH6";
}

group MapSugarSaltyFrequency(source src : QR, target tgt : Obs) {
  src.answer as answer then {
    answer.valueCoding as coding -> tgt.value = create('CodeableConcept') as cc,
      cc.coding = coding "SetValueCoding";
  } "ProcessAnswer";
}
